// ═══════════════════════════════════════════════════
// Validate & Sanitize v2.0 — SP v4.0 compliant
// Добавлены: niche_cluster, priority_engines, cms,
// project_phase, intent awareness
// ═══════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;
const {
  niche, city, project_id, target_url,
  competitors, pages, niche_cluster,
  priority_engines, cms, project_phase,
  relink_frequency
} = body;

// === Обязательные поля ===
if (!niche || typeof niche !== 'string' || niche.length > 200)
  throw new Error('Поле "niche" обязательно (string, max 200)');
if (!city || typeof city !== 'string' || city.length > 100)
  throw new Error('Поле "city" обязательно (string, max 100)');
if (!project_id || typeof project_id !== 'string')
  throw new Error('Поле "project_id" обязательно');

// === Санитизация ===
const sanitize = (s) => String(s).replace(/[{}\[\]"'`;$\\]/g, '').trim();
const safeNiche = sanitize(niche);
const safeCity = sanitize(city);

// === Niche Cluster — SP v4.0 ===
const validClusters = ['commercial_local', 'commercial_national', 'info', 'ecom', 'saas'];
const safeCluster = validClusters.includes(niche_cluster) ? niche_cluster : 'commercial_local';

// === Priority Engines — [Я]/[G]/[ОБА] ===
const validEngines = ['yandex', 'google', 'both'];
const safeEngines = validEngines.includes(priority_engines) ? priority_engines : 'both';

// === CMS ===
const validCms = ['wordpress', 'bitrix', 'tilda', 'custom', 'other'];
const safeCms = validCms.includes((cms || '').toLowerCase()) ? cms.toLowerCase() : 'custom';

// === Project Phase ===
const validPhases = ['setup', 'growth', 'maintenance', 'recovery'];
const safePhase = validPhases.includes(project_phase) ? project_phase : 'growth';

// === URL валидация ===
let safeTargetUrl = '';
if (target_url) {
  try { new URL(target_url); safeTargetUrl = target_url; }
  catch(e) { safeTargetUrl = ''; }
}

// === Конкуренты ===
let competitorsList = [];
if (Array.isArray(competitors) && competitors.length > 0) {
  competitorsList = competitors.slice(0, 5).map(c => sanitize(c));
}

// === Страницы ===
let pagesList = [];
if (Array.isArray(pages) && pages.length > 0) {
  pagesList = pages;
}

// === Динамический embed_query (без хардкода года) ===
const embed_query = `${safeNiche} ${safeCity} перелинковка внутренние ссылки анкоры навигация структура кластеры ${safeCluster} SEO`;

return [{ json: {
  niche: safeNiche,
  city: safeCity,
  project_id: project_id,
  target_url: safeTargetUrl,
  competitors: competitorsList,
  pages_input: pagesList,
  niche_cluster: safeCluster,
  priority_engines: safeEngines,
  cms: safeCms,
  project_phase: safePhase,
  relink_frequency: relink_frequency || 'monthly',
  embed_query: embed_query,
  workflow_version: 'v4.0_pro'
}}];

// ═══════════════════════════════════════════════════
// Format RAG Context v2.0
// + Backlink magnets, навигационные паттерны полные,
// + КФ/E-E-A-T контекст
// ═══════════════════════════════════════════════════

let personaResults = [], structResults = [], linksHistory = [];
try { personaResults = $('RAG seo_personas').first().json.result || []; } catch(e) {}
try { structResults = $('RAG page_structures').first().json.result || []; } catch(e) {}
try { linksHistory = $('RAG links_history').first().json.result || []; } catch(e) {}

// === Персоны (без обрезки до 200 символов) ===
let personaContext = '';
if (personaResults.length > 0) {
  personaContext = '=== ЦЕЛЕВАЯ АУДИТОРИЯ ===\n';
  personaResults.forEach((r, i) => {
    const p = r.payload || {};
    personaContext += `Персона ${i+1}: ${p.persona_name || 'N/A'}`;
    if (p.navigation_patterns) personaContext += `\n  Навигация: ${typeof p.navigation_patterns === 'string' ? p.navigation_patterns : JSON.stringify(p.navigation_patterns).substring(0, 500)}`;
    if (p.pain_points) personaContext += `\n  Боли: ${typeof p.pain_points === 'string' ? p.pain_points : JSON.stringify(p.pain_points).substring(0, 500)}`;
    if (p.conversion_triggers) personaContext += `\n  Триггеры конверсии: ${typeof p.conversion_triggers === 'string' ? p.conversion_triggers : JSON.stringify(p.conversion_triggers).substring(0, 300)}`;
    personaContext += '\n\n';
  });
}

// === Структуры конкурентов ===
let structContext = '';
if (structResults.length > 0) {
  structContext = '\n=== СТРУКТУРЫ КОНКУРЕНТОВ (ТОП-10) ===\n';
  structResults.forEach((r, i) => {
    const p = r.payload || {};
    structContext += `Конкурент ${i+1}: ${p.niche || ''} | Кластеров: ${p.clusters_count || 'N/A'} | Глубина: ${p.max_depth || 'N/A'}`;
    if (p.linking_patterns) structContext += ` | Паттерны: ${JSON.stringify(p.linking_patterns).substring(0, 300)}`;
    structContext += '\n';
  });
}

// === История перелинковок ===
let histContext = '';
if (linksHistory.length > 0) {
  histContext = '\n=== ИСТОРИЯ ПЕРЕЛИНКОВОК ===\n';
  linksHistory.forEach((r, i) => {
    const p = r.payload || {};
    histContext += `Анализ ${i+1}: ${p.niche || ''} | Ссылок: ${p.links_count || 0} | QC: ${p.qc_score || 'N/A'}%\n`;
  });
}

// === Backlink Magnets ===
let backlinkContext = '';
try {
  const blData = $('Fetch Backlinks').first().json;
  const blList = blData.list || blData || [];
  if (Array.isArray(blList) && blList.length > 0) {
    backlinkContext = '\n=== BACKLINK MAGNETS (страницы с внешними ссылками) ===\n';
    blList.slice(0, 10).forEach((b, i) => {
      backlinkContext += `${i+1}. ${b.recommended_url || b.url || ''} | Внешних ссылок: ${b.backlinks_count || 0} | DR: ${b.domain_rating || 'N/A'}\n`;
    });
    backlinkContext += 'ВАЖНО: Эти страницы передают link equity — используй их как ИСТОЧНИКИ внутренних ссылок на коммерческие страницы.\n';
  }
} catch(e) {}

return [{ json: {
  rag_context: (personaContext || 'Нет данных о персонах.') + structContext + histContext + backlinkContext,
  rag_persona_sources: personaResults.length,
  rag_struct_sources: structResults.length,
  rag_history_sources: linksHistory.length,
  has_backlink_data: backlinkContext.length > 0
}}];

// ═══════════════════════════════════════════════════════════
// Build Links Prompt v4.0 — SP v4.0 полная реализация
// [Я]/[G] маркировка · Intent segmentation · КФ · E-E-A-T
// Few-shot анкоры · Niche cluster адаптация
// Chunked generation для >10 страниц
// ═══════════════════════════════════════════════════════════

const response = $('Fetch Page Structures v2').first().json;
const validate = $('Validate & Sanitize v2.0').first().json;
const ragInfo = $('Format RAG Context v2').first().json;

const rows = response.list || [];

// === Merge with pages_input ===
let allPages = [...rows];
if (validate.pages_input && validate.pages_input.length > 0) {
  const existingUrls = new Set(rows.map(r => r.recommended_url));
  validate.pages_input.forEach(p => {
    if (!existingUrls.has(p.url)) {
      allPages.push({
        page_type: p.type || 'page',
        cluster_name: p.cluster || '',
        recommended_url: p.url,
        main_keyword: p.keyword || '',
        total_blocks: p.blocks || 0,
        intent: p.intent || 'transactional',
        backlinks_count: p.backlinks_count || 0
      });
    }
  });
}

if (allPages.length === 0) {
  throw new Error('Нет страниц для перелинковки. Сначала выполните шаг 04 (Структура страниц).');
}

// === Pages Context с intent и backlinks ===
let pagesContext = `\n=== СТРАНИЦЫ ПРОЕКТА (${allPages.length} шт.) ===\n\n`;
allPages.forEach((r, i) => {
  const intent = r.intent || 'transactional';
  const bl = r.backlinks_count || 0;
  pagesContext += `${i+1}. [${(r.page_type||'').toUpperCase()}] [${intent.toUpperCase()}] ${r.cluster_name||''}`;
  pagesContext += ` | URL: ${r.recommended_url||''}`;
  pagesContext += ` | Ключ: ${r.main_keyword||''}`;
  pagesContext += ` | Блоков: ${r.total_blocks||0}`;
  if (bl > 0) pagesContext += ` | 🔗Внешних: ${bl}`;
  pagesContext += '\n';
});

// === Cluster Map ===
const clusters = {};
allPages.forEach(p => {
  const cl = p.cluster_name || 'uncategorized';
  if (!clusters[cl]) clusters[cl] = [];
  clusters[cl].push({ url: p.recommended_url || '', intent: p.intent || 'transactional' });
});

let clusterMap = '\n=== КАРТА КЛАСТЕРОВ ===\n';
Object.entries(clusters).forEach(([name, pages]) => {
  const intents = pages.map(p => p.intent);
  const transCount = intents.filter(i => i === 'transactional').length;
  clusterMap += `Кластер "${name}": ${pages.length} стр. (${transCount} коммерч.) → ${pages.slice(0,5).map(p=>p.url).join(', ')}\n`;
});

// ═══════════════════════════════════════════
// [Я]/[G] ENGINE INSTRUCTIONS — SP v4.0
// ═══════════════════════════════════════════
const engines = validate.priority_engines;

let engineInstructions = '';
if (engines === 'both' || engines === 'yandex') {
  engineInstructions += `\n[Я] ЯНДЕКС — обязательные типы ссылок:\n`;
  engineInstructions += `  • КФ-ССЫЛКИ: каждая страница → ссылка на Цены, Гарантии, Сертификаты, Команду, Отзывы\n`;
  engineInstructions += `  • ГЕОЗАВИСИМЫЕ: /район-услуга/ перелинковка (если есть гео-страницы)\n`;
  engineInstructions += `  • ПФ-ОПТИМИЗАЦИЯ: ссылки в зонах максимального внимания (первый экран, после H1)\n`;
  engineInstructions += `  • Яндекс.Бизнес/2GIS: ссылки на карточки из Footer\n\n`;
}
if (engines === 'both' || engines === 'google') {
  engineInstructions += `[G] GOOGLE — обязательные типы ссылок:\n`;
  engineInstructions += `  • E-E-A-T: ссылки на авторские страницы, credentials, лицензии\n`;
  engineInstructions += `  • SCHEMA-ALIGNED: Service→FAQ, FAQ→Review, Review→LocalBusiness (согласно Schema.org)\n`;
  engineInstructions += `  • TOPICAL AUTHORITY: hub→spoke внутри semantic cluster (pillar→cluster)\n`;
  engineInstructions += `  • CWV-SAFE: не перегружай страницу ссылками (макс 100 внутренних на страницу)\n\n`;
}
engineInstructions += `[ОБА] УНИВЕРСАЛЬНЫЕ:\n`;
engineInstructions += `  • Иерархия: главная → категории → услуги\n`;
engineInstructions += `  • Breadcrumbs, main_menu, footer — обязательны\n`;
engineInstructions += `  • Глубина: любая страница ≤3 клика от главной\n`;

// === Intent Strategy ===
const intentStrategy = `\nINTENT-BASED LINKING (ОБЯЗАТЕЛЬНО):\n- TRANSACTIONAL страницы (услуги, цены): ≥5 входящих, ≤3 исходящих\n  Цель: максимум link equity на конверсионные страницы\n- INFORMATIONAL (блог, FAQ): ≤3 входящих, ≥3 исходящих на коммерческие\n  Цель: передача authority через content links\n- NAVIGATIONAL (главная, категории): hub-ноды, ≥5 исходящих\n  Цель: распределение PageRank по всей структуре\n\nBACKLINK MAGNETS: страницы с внешними ссылками — приоритетные ИСТОЧНИКИ\nвнутренних ссылок. Передают authority на коммерческие.\n`;

// === Niche Cluster Adaptation ===
const clusterAdaptation = {
  commercial_local: 'ФОКУС: КФ-ссылки, Local SEO, геозависимые страницы, карточки организации. Каждая услуга → ссылка на район.',
  commercial_national: 'ФОКУС: Ссылочный профиль, E-E-A-T, Programmatic (Услуга × Город). Featured Snippets через FAQ-перелинковку.',
  ecom: 'ФОКУС: Категории → подкатегории → товары. Фильтры → canonical. Breadcrumbs обязательны. Product schema linking.',
  saas: 'ФОКУС: Blog Pipeline → Feature Pages. Entity SEO. Мультиязычность (hreflang). Topic clusters.',
  info: 'ФОКУС: Content Quality, Pillar→Cluster, авторские страницы. YMYL-требования. Decay-мониторинг.'
};
const nicheNote = clusterAdaptation[validate.niche_cluster] || clusterAdaptation.commercial_local;

// === Few-shot Anchor Examples ===
const anchorExamples = `\nПРИМЕРЫ КАЧЕСТВЕННЫХ АНКОРОВ:\n✓ "лечение кариеса без боли" — ключ + УТП\n✓ "наши стоматологи с 15-летним опытом" — E-E-A-T\n✓ "цены на имплантацию зубов в ${validate.city}" — КФ [Я] + гео\n✓ "подробнее об отбеливании" — навигационный\n✓ "читать отзывы пациентов" — social proof\n✓ "гарантия 5 лет на все работы" — КФ [Я]\n✗ НЕ ИСПОЛЬЗОВАТЬ: "подробнее", "нажмите здесь", "читать далее" (пустые анкоры)\n✗ НЕ ИСПОЛЬЗОВАТЬ: повторение одного анкора >2 раз\n✗ НЕ ИСПОЛЬЗОВАТЬ: keyword stuffing в анкорах\n`;

// === CMS Adaptation ===
const cmsNotes = {
  wordpress: 'CMS WordPress: sidebar виджеты, footer меню, шорткоды CTA доступны.',
  bitrix: 'CMS Bitrix: компоненты навигации, включаемые области. Sidebar через компонент.',
  tilda: 'CMS Tilda: ограничения — нет sidebar, footer ограничен. Используй content и CTA типы.',
  custom: 'CMS кастомная: все типы ссылок доступны.',
  other: 'CMS: проверь доступность sidebar и footer.'
};
const cmsNote = cmsNotes[validate.cms] || cmsNotes.custom;

// ═══════════════════════════════════════════
// SYSTEM PROMPT
// ═══════════════════════════════════════════
const systemPrompt = `Ты Senior SEO-архитектор внутренней перелинковки. Экспертиза: Яндекс + Google, коммерческое SEO.

ЗАДАЧА: построить полный граф внутренней перелинковки между ВСЕМИ страницами проекта.

${ragInfo.rag_context}
${pagesContext}
${clusterMap}

НИШЕВАЯ АДАПТАЦИЯ (${validate.niche_cluster}):
${nicheNote}

${cmsNote}

${engineInstructions}
${intentStrategy}

ПРИНЦИПЫ ПЕРЕЛИНКОВКИ (в порядке приоритета):

1. ИЕРАРХИЯ: главная → категории → подкатегории → услуги/статьи
2. КЛАСТЕРНАЯ СВЯЗНОСТЬ: ВСЕ страницы одного кластера связаны (hub & spoke)
3. МЕЖКЛАСТЕРНЫЕ МОСТЫ: 2-3 тематических ссылки между смежными кластерами
4. PAGERANK FLOW: коммерческие/transactional страницы получают БОЛЬШЕ входящих
5. BACKLINK MAGNETS: страницы с внешними ссылками → источники internal links на commercial
6. НЕТ СИРОТ: каждая страница имеет минимум 3 входящие ссылки
7. АНКОРЫ: естественные, разнообразные, с ключевым словом целевой страницы
8. ГЛУБИНА КЛИКА: любая страница ≤3 клика от главной
9. RECIPROCAL LINKS: избегать взаимных ссылок A↔B (макс 15%)
10. КФ-ПОКРЫТИЕ [Я]: каждая коммерческая → ссылки на цены/гарантии/отзывы/команду
11. E-E-A-T LINKING [G]: ссылки на авторов, сертификаты, исследования

${anchorExamples}

ТИПЫ ССЫЛОК (link_type):
- main_menu: навигационная ссылка из главного меню
- breadcrumb: хлебные крошки
- content: контекстная ссылка в тексте
- sidebar: ссылка из боковой панели
- related: блок "Похожие услуги/статьи"
- footer: ссылка из подвала
- cta: call-to-action блок

Для каждой ссылки ОБЯЗАТЕЛЬНО:
- from_url: URL страницы-источника (СТРОГО из списка страниц выше!)
- to_url: URL целевой страницы (СТРОГО из списка страниц выше!)
- anchor: текст анкора (естественный, разнообразный)
- link_type: СТРОГО одно из [main_menu, breadcrumb, content, sidebar, related, footer, cta]
- priority: 1-100 (1 = самая важная)
- context: описание WHERE на странице и ЗАЧЕМ размещена ссылка
- engine_tag: "Я" или "G" или "ОБА"
- intent_flow: "transactional→transactional" или "informational→transactional" и т.д.

КРИТИЧЕСКИЕ ПРАВИЛА:
- ИСПОЛЬЗУЙ ТОЛЬКО URL из списка страниц выше. НЕ ПРИДУМЫВАЙ новые URL!
- Каждый URL должен быть и источником, и целью хотя бы одной ссылки
- Минимум 7 типов ссылок задействовано

Ответь СТРОГО JSON (без markdown, без комментариев):
{"internal_links":[...], "orphan_check": {"all_pages_linked": true/false, "orphans": []}, "graph_stats": {"total_links": N, "avg_incoming": N, "max_depth": N, "type_distribution": {}}}`;

// ═══════════════════════════════════════════
// USER PROMPT
// ═══════════════════════════════════════════
const minLinks = Math.max(30, allPages.length * 5);
const userPrompt = `НИША: ${validate.niche} | ГОРОД: ${validate.city} | КЛАСТЕР: ${validate.niche_cluster}\nДВИЖКИ: ${validate.priority_engines.toUpperCase()} | CMS: ${validate.cms}\nСТРАНИЦ: ${allPages.length} | КЛАСТЕРОВ: ${Object.keys(clusters).length}\n\nПострой полный граф перелинковки. Требования:\n• Минимум ${minLinks} ссылок\n• Каждая страница: мин. 3 входящих + 2 исходящих\n• Используй все 7 типов ссылок\n• Анкоры разнообразные (не повторяй один и тот же)\n• Маркируй каждую ссылку engine_tag: Я/G/ОБА\n• Указывай intent_flow для каждой ссылки\n• ИСПОЛЬЗУЙ ТОЛЬКО URL из списка страниц!\n• Проверь: нет сирот, глубина ≤3 клика\nОтветь СТРОГО JSON.`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 16000,
  temperature: 0.2,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

// === Collect valid URLs for verification later ===
const validUrlSet = allPages.map(p => p.recommended_url).filter(Boolean);

return [{ json: {
  groq_payload: payload,
  project_id: validate.project_id,
  niche: validate.niche,
  city: validate.city,
  niche_cluster: validate.niche_cluster,
  priority_engines: validate.priority_engines,
  cms: validate.cms,
  pages_count: allPages.length,
  clusters_count: Object.keys(clusters).length,
  cluster_map: clusters,
  valid_urls: validUrlSet,
  min_links: minLinks
}}];

// ═══════════════════════════════════════════════════
// Parse & Validate Links v2.0
// Weighted QC scoring · URL verification
// Intent flow tracking · Engine tag validation
// ═══════════════════════════════════════════════════

const groqResponse = $input.first().json;
const batchInfo = $('Build Links Prompt v4.0').first().json;

// === Groq error handling ===
if (groqResponse.error) {
  return [{ json: {
    links_count: 0, nocodb_payload: [], verified_links: [],
    error: groqResponse.error.message || 'Groq error',
    groq_tokens: 0, qc_score: 0, graph_stats: null,
    orphan_check: null, hallucinated_links: []
  }}];
}

// === Parse JSON response ===
const rawContent = groqResponse?.choices?.[0]?.message?.content || '';
let cleanJson = rawContent.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (err) {
  const objMatch = cleanJson.match(/\{[\s\S]+\}/);
  if (objMatch) {
    try { parsed = JSON.parse(objMatch[0]); } catch(e2) {}
  }
  if (!parsed) {
    return [{ json: {
      links_count: 0, nocodb_payload: [], verified_links: [],
      error: 'Invalid JSON: ' + rawContent.substring(0, 300),
      groq_tokens: groqResponse?.usage?.total_tokens || 0,
      qc_score: 0, graph_stats: null, orphan_check: null,
      hallucinated_links: []
    }}];
  }
}

if (Array.isArray(parsed)) parsed = { internal_links: parsed };
else if (parsed && !parsed.internal_links && parsed.from_url) parsed = { internal_links: [parsed] };

const validTypes = ['main_menu', 'breadcrumb', 'content', 'sidebar', 'related', 'footer', 'cta'];
const validEngines = ['Я', 'G', 'ОБА'];

// === Valid URLs set (from page_structures) ===
const validUrlSet = new Set(batchInfo.valid_urls || []);

// === Dedup + Validate + URL Verify ===
const seen = new Set();
const verified = [];
const hallucinated = [];

(parsed.internal_links || []).forEach((l, idx) => {
  const key = (l.from_url || '') + '→' + (l.to_url || '') + '→' + (l.link_type || '');
  if (seen.has(key)) return;
  seen.add(key);

  // Skip self-links
  if (l.from_url && l.to_url && l.from_url === l.to_url) return;

  const fromOk = validUrlSet.has(l.from_url);
  const toOk = validUrlSet.has(l.to_url);

  const link = {
    project_id: batchInfo.project_id,
    from_url: l.from_url || '',
    to_url: l.to_url || '',
    anchor: l.anchor || '',
    link_type: validTypes.includes(l.link_type) ? l.link_type : 'content',
    priority: Math.min(Math.max(l.priority || (idx + 1), 1), 100),
    context: l.context || '',
    engine_tag: validEngines.includes(l.engine_tag) ? l.engine_tag : 'ОБА',
    intent_flow: l.intent_flow || '',
    status: 'pending',
    version: 'v4.0',
    created_at: new Date().toISOString()
  };

  if (fromOk && toOk) {
    verified.push(link);
  } else {
    hallucinated.push({
      ...link,
      reason: !fromOk ? 'from_url not in page_structures' : 'to_url not in page_structures'
    });
  }
});

// ═══════════════════════════════════════════
// Weighted QC Scoring v2.0
// ═══════════════════════════════════════════
let qcScore = 100;
const issues = [];

// 1. Минимум ссылок (-25)
const minLinks = batchInfo.min_links || 30;
if (verified.length < minLinks) {
  const penalty = Math.min(25, Math.round((1 - verified.length / minLinks) * 25));
  qcScore -= penalty;
  issues.push(`Мало ссылок: ${verified.length}/${minLinks} (-${penalty})`);
}

// 2. Hallucinated URLs (-30 max)
const hallRate = verified.length + hallucinated.length > 0
  ? hallucinated.length / (verified.length + hallucinated.length) * 100 : 0;
if (hallRate > 5) {
  const penalty = Math.min(30, Math.round(hallRate * 0.6));
  qcScore -= penalty;
  issues.push(`Hallucinated URLs: ${hallRate.toFixed(1)}% (${hallucinated.length} шт.) (-${penalty})`);
}

// 3. Orphans — страницы с <2 входящих (-20)
const incomingCount = {};
verified.forEach(l => { incomingCount[l.to_url] = (incomingCount[l.to_url] || 0) + 1; });
const allUrls = [...validUrlSet];
const orphans = allUrls.filter(u => !incomingCount[u] || incomingCount[u] < 2);
if (orphans.length > 0) {
  const penalty = Math.min(20, orphans.length * 4);
  qcScore -= penalty;
  issues.push(`Сироты (<2 входящих): ${orphans.length} шт. (-${penalty})`);
}

// 4. Link type diversity (-15)
const typeDistribution = {};
verified.forEach(l => { typeDistribution[l.link_type] = (typeDistribution[l.link_type] || 0) + 1; });
const typesUsed = Object.keys(typeDistribution).length;
if (typesUsed < 4) {
  const penalty = Math.min(15, (4 - typesUsed) * 5);
  qcScore -= penalty;
  issues.push(`Мало типов ссылок: ${typesUsed}/7 (${Object.keys(typeDistribution).join(', ')}) (-${penalty})`);
}

// 5. Reciprocal ratio (-10)
const reciprocal = verified.filter(l =>
  verified.some(l2 => l2.from_url === l.to_url && l2.to_url === l.from_url)
);
const reciprocalRatio = verified.length > 0 ? reciprocal.length / verified.length : 0;
if (reciprocalRatio > 0.15) {
  qcScore -= 10;
  issues.push(`Высокий reciprocal: ${(reciprocalRatio * 100).toFixed(0)}% (-10)`);
}

// 6. Missing engine_tag (-5) — only if priority_engines=both
const engineDist = {};
verified.forEach(l => { engineDist[l.engine_tag] = (engineDist[l.engine_tag] || 0) + 1; });
if (batchInfo.priority_engines === 'both' && Object.keys(engineDist).length < 2) {
  qcScore -= 5;
  issues.push(`Нет [Я]/[G] разделения (-5)`);
}

qcScore = Math.max(0, qcScore);

// === Graph Stats ===
const outgoingCount = {};
verified.forEach(l => { outgoingCount[l.from_url] = (outgoingCount[l.from_url] || 0) + 1; });
const avgIncoming = allUrls.length > 0
  ? Object.values(incomingCount).reduce((a, b) => a + b, 0) / allUrls.length : 0;

return [{ json: {
  links_count: verified.length,
  nocodb_payload: verified,
  verified_links: verified,
  hallucinated_links: hallucinated,
  hallucination_rate: hallRate.toFixed(1),
  groq_tokens: groqResponse?.usage?.total_tokens || 0,
  error: null,
  qc_score: qcScore,
  issues: issues.length > 0 ? issues : null,
  graph_stats: {
    total_links: verified.length,
    avg_incoming: avgIncoming.toFixed(1),
    max_outgoing: Math.max(...Object.values(outgoingCount), 0),
    pages_covered: new Set([...verified.map(l => l.from_url), ...verified.map(l => l.to_url)]).size,
    pages_total: allUrls.length
  },
  orphan_check: {
    all_pages_linked: orphans.length === 0,
    orphans: orphans.slice(0, 10)
  },
  type_distribution: typeDistribution,
  engine_distribution: engineDist,
  reciprocal_ratio: reciprocalRatio,
  valid_urls_count: validUrlSet.size
}}];

// ═══════════════════════════════════════════════════
// PageRank Calculator
// Iterative PageRank on generated link graph
// Damping factor 0.85, 20 iterations
// Detects PageRank leaks to non-commercial pages
// ═══════════════════════════════════════════════════

const linkData = $input.first().json;
const links = linkData.verified_links || linkData.nocodb_payload || [];

if (links.length === 0) {
  return [{ json: { ...linkData, pagerank: [], top5: [], leaks: [], leak_warning: false }}];
}

const damping = 0.85;
const iterations = 20;

// Build URL set
const allUrls = [...new Set([...links.map(l => l.from_url), ...links.map(l => l.to_url)])];
const N = allUrls.length;

if (N === 0) {
  return [{ json: { ...linkData, pagerank: [], top5: [], leaks: [], leak_warning: false }}];
}

// Initialize PageRank
let pr = {};
allUrls.forEach(u => pr[u] = 1 / N);

// Build outgoing map
const outgoing = {};
links.forEach(l => {
  if (!outgoing[l.from_url]) outgoing[l.from_url] = [];
  outgoing[l.from_url].push(l.to_url);
});

// Build incoming map
const incoming = {};
links.forEach(l => {
  if (!incoming[l.to_url]) incoming[l.to_url] = [];
  incoming[l.to_url].push(l.from_url);
});

// Iterate
for (let i = 0; i < iterations; i++) {
  const newPr = {};
  allUrls.forEach(u => {
    let sum = 0;
    (incoming[u] || []).forEach(src => {
      const outCount = (outgoing[src] || []).length;
      if (outCount > 0) sum += pr[src] / outCount;
    });
    newPr[u] = (1 - damping) / N + damping * sum;
  });
  pr = newPr;
}

// Sort by PageRank
const ranked = Object.entries(pr)
  .sort((a, b) => b[1] - a[1])
  .map(([url, score]) => ({ url, pagerank: parseFloat(score.toFixed(6)) }));

// Detect leaks: check if top-5 PR pages are commercial
// Use intent_flow from links to determine commercial pages
const commercialUrls = new Set();
links.forEach(l => {
  if (l.intent_flow && l.intent_flow.includes('transactional')) {
    commercialUrls.add(l.to_url);
  }
});

const leaks = ranked.slice(0, 5).filter(r => !commercialUrls.has(r.url) && commercialUrls.size > 0);

// PageRank concentration: % of total PR in top-3 pages
const totalPr = Object.values(pr).reduce((a, b) => a + b, 0);
const top3Pr = ranked.slice(0, 3).reduce((a, r) => a + r.pagerank, 0);
const concentration = totalPr > 0 ? (top3Pr / totalPr * 100).toFixed(1) : 0;

return [{ json: {
  ...linkData,
  pagerank: ranked,
  pagerank_top5: ranked.slice(0, 5),
  pagerank_leaks: leaks,
  pagerank_leak_warning: leaks.length > 2,
  pagerank_concentration: concentration
}}];

// ═══════════════════════════════════════════════════
// Quality Gate v2.0 — двухуровневый
// Combined score: QC (0.6) + ML (0.4)
// Три исхода: PASS / REVIEW / REJECT
// ═══════════════════════════════════════════════════

const data = $('PageRank Calculator').first().json;
let mlResponse = {};
try { mlResponse = $('ML Link Value').first().json || {}; } catch(e) {}

const qcScore = data.qc_score || 0;
const mlScore = mlResponse.score != null ? mlResponse.score : qcScore; // fallback to QC if ML unavailable
const combinedScore = Math.round(qcScore * 0.6 + mlScore * 0.4);

const hallRate = parseFloat(data.hallucination_rate || 0);
const prLeaks = (data.pagerank_leaks || []).length;

// === Decision Logic ===
let decision = 'pass';
let status = 'active';
const reasons = [];

// REJECT conditions
if (combinedScore < 50) { decision = 'reject'; reasons.push(`Combined score ${combinedScore} < 50`); }
if (hallRate > 15) { decision = 'reject'; reasons.push(`Hallucination rate ${hallRate}% > 15%`); }
if (data.links_count === 0) { decision = 'reject'; reasons.push('Zero links generated'); }

// REVIEW conditions (only if not already rejected)
if (decision !== 'reject') {
  if (combinedScore < 65) { decision = 'review'; status = 'review_needed'; reasons.push(`Combined score ${combinedScore} < 65`); }
  if (hallRate > 5) { decision = 'review'; status = 'review_needed'; reasons.push(`Hallucination rate ${hallRate}%`); }
  if (prLeaks > 2) { decision = 'review'; status = 'review_needed'; reasons.push(`PageRank leaks: ${prLeaks}`); }
}

return [{ json: {
  ...data,
  ml_score: mlScore,
  ml_label: mlResponse.label || null,
  ml_confidence: mlResponse.confidence || null,
  combined_score: combinedScore,
  gate_decision: decision,
  gate_status: status,
  gate_reasons: reasons
}}];

